const c=(r,e)=>{switch(r){case"payment":case"receipt":return e==="bank"?"voucher-form--bank":"voucher-form--cash";case"contra":return"voucher-form--contra";case"journal":return"voucher-form--journal";case"debit-note":case"sales":return"voucher-form--debit-note";case"credit-note":case"purchase":return"voucher-form--credit-note";case"tax-invoice":return"voucher-form--bank";default:return e==="bank"?"voucher-form--bank":"voucher-form--cash"}};export{c as r};
